void invert_mapping(cl_global float *input, cl_global float *output, int npoints, int nfeatures) {
    int point_id = get_global_id(0);
    int i;

    if(point_id < npoints){
        for(i=0;i<nfeatures;i++)
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
    }
}

void kmeansPoint(cl_global float *features,
            int     nfeatures,
            int     npoints,
            int     nclusters,
            cl_global int *membership,
            cl_global float *clusters,
            cl_global float *block_clusters,
            cl_global int *block_deltas,
            const cl_global float *t_features,
            const cl_global float *t_features_flipped,
            const cl_global float *t_clusters)
{
    const unsigned int block_id = get_num_groups(0)*get_group_id(1)+get_group_id(0);
    const unsigned int point_id = block_id*THREADS_PER_BLOCK + get_local_id(0);

    int index = -1;

    if (point_id < npoints)
    {
        int i, j;
        float min_dist = FLT_MAX;
        float dist;

        for (i=0; i<nclusters; i++) {
            int cluster_base_index = i*nfeatures;
            float ans=0.0f;

            for (j=0; j < nfeatures; j)
            {
                int addr = point_id + j*npoints;
                float diff = (t_features[addr] - t_clusters[cluster_base_index + j]);
                ans += diff*diff;
                j++;
            }
            dist = ans;

            if (dist < min_dist) {
                min_dist = dist;
                index    = i;
            }
        }
    }

    if (point_id < npoints)
    {
        membership[point_id] = index;
    }
}

