        if (err != CL_SUCCESS) return;
    }

    context = clCreateContext(NULL, 1, &device, NULL, NULL, &err);
    if (err != CL_SUCCESS) return;

    cl_command_queue queue = clCreateCommandQueue(context, device, 0, &err);
    if (err != CL_SUCCESS) {
        clReleaseContext(context);
        return;
    }

    feature_flipped_d = (float*)clEnqueueCreateBuffer(context, CL_MEM_READ_WRITE, npoints*nfeatures*sizeof(float), NULL, &err);
    if (err != CL_SUCCESS) {
        clReleaseCommandQueue(queue);
        clReleaseContext(context);
        return;
    }

    clEnqueueWriteBuffer(queue, (cl_mem)feature_flipped_d, CL_TRUE, 0, npoints*nfeatures*sizeof(float), features[0], 0, NULL, NULL);

    feature_d = (float*)clEnqueueCreateBuffer(context, CL_MEM_READ_WRITE, npoints*nfeatures*sizeof(float), NULL, &err);

    size_t global_invert_size = num_blocks * num_threads;
    const char *source =
        "void invert_mapping(cl_global float *input, cl_global float *output, int npoints, int nfeatures) {\n"
        "    int point_id = get_global_id(0);\n"
        "    int i;\n"
